}
}', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:59+00:00", "source_pdf_sha1": "cd9f00796c41", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114190", "c": "445", "s": "2108", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "程式設計概要", "year": "114", "exam_name": "114年特種考試地方政府公務人員考試、離島地區公務人員考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "islands", "civil_category": "資訊處理"}'::jsonb, NULL),
